class Solution:
    def prevPermOpt1(self, arr):
        n = len(arr)
        best = None
        for i in range(n):
            for j in range(i + 1, n):
                cand = list(arr)
                cand[i], cand[j] = cand[j], cand[i]
                if cand < arr and (best is None or cand > best):
                    best = cand
        return best if best is not None else list(arr)

